          "description": "Gemini service for generating message templates",
          "diffs": [
            {
              "target": "",
              "replacement": "\nimport { GoogleGenAI } from \"@google/genai\";\nimport { ChurchLeader, Meeting } from \"../types\";\n\nconst ai = new GoogleGenAI({ apiKey: process.env.API_KEY });\n\nexport const generateWhatsAppTemplate = async (meeting: Meeting, tone: string = 'pastoral y amable'): Promise<string> => {\n  try {\n    const prompt = `Actúa como un coordinador de eventos para una organización cristiana. \n    Escribe una plantilla de mensaje de WhatsApp para invitar a pastores a una reunión.\n    \n    Datos de la reunión:\n    - Nombre: ${meeting.name}\n    - Fecha: ${meeting.date}\n    - Hora: ${meeting.time}\n    - Sede: ${meeting.venue}\n    \n    Usa estas variables dinámicas exactamente así:\n    {{nombre_completo}}, {{nombre_iglesia}}, {{reunion_asignada}}, {{fecha}}, {{sede}}, {{cantidad_libros}}\n    \n    Tono: ${tone}.\n    El mensaje debe ser breve, claro y con un llamado a la acción. \n    Asegúrate de mencionar que deben retirar {{cantidad_libros}} libros en la sede.\n    Solo devuelve el texto de la plantilla.`;\n\n    const response = await ai.models.generateContent({\n      model: 'gemini-3-flash-preview',\n      contents: prompt,\n    });\n\n    return response.text || 'Error al generar plantilla';\n  } catch (error) {\n    console.error(\"Gemini Template Error:\", error);\n    return `Hola {{nombre_completo}}, bendiciones. Le invitamos a la reunión {{reunion_asignada}} el día {{fecha}} en {{sede}}. No olvide retirar sus {{cantidad_libros}} libros. ¡Le esperamos!`;\n  }\n};\n\nexport const parseTemplate = (template: string, church: ChurchLeader, meeting: Meeting): string => {\n  let message = template;\n  message = message.replace(/{{nombre_completo}}/g, church.fullName);\n  message = message.replace(/{{nombre_iglesia}}/g, church.churchName);\n  message = message.replace(/{{reunion_asignada}}/g, meeting.name);\n  message = message.replace(/{{fecha}}/g, meeting.date);\n  message = message.replace(/{{sede}}/g, meeting.venue);\n  message = message.replace(/{{cantidad_libros}}/g, church.bookQuantity.toString());\n  return message;\n};\n"
            }
          ]
