          "description": "Church leader list with filtering and search",
          "diffs": [
            {
              "target": "",
              "replacement": "\nimport React, { useState } from 'react';\nimport { ChurchLeader, Meeting, ZONES, ContactStatus } from '../types';\nimport { Search, Filter, MessageCircle, FileDown, MoreVertical } from 'lucide-react';\n\ninterface Props {\n  churches: ChurchLeader[];\n  meetings: Meeting[];\n  onOpenMessenger: (church: ChurchLeader) => void;\n}\n\nconst ChurchManagement: React.FC<Props> = ({ churches, meetings, onOpenMessenger }) => {\n  const [searchTerm, setSearchTerm] = useState('');\n  const [zoneFilter, setZoneFilter] = useState('all');\n  const [meetingFilter, setMeetingFilter] = useState('all');\n\n  const filteredChurches = churches.filter(c => {\n    const matchesSearch = c.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || \n                         c.churchName.toLowerCase().includes(searchTerm.toLowerCase());\n    const matchesZone = zoneFilter === 'all' || c.zone === zoneFilter;\n    const matchesMeeting = meetingFilter === 'all' || c.meetingId === meetingFilter;\n    return matchesSearch && matchesZone && matchesMeeting;\n  });\n\n  const getMeetingName = (id: string) => meetings.find(m => m.id === id)?.name || 'Sin asignar';\n\n  return (\n    <div className=\"bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden\">\n      <div className=\"p-4 border-b border-slate-100 bg-slate-50/50 space-y-4 md:space-y-0 md:flex md:items-center md:justify-between\">\n        <div className=\"relative flex-1 max-w-md\">\n          <Search className=\"absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4\" />\n          <input \n            type=\"text\" \n            placeholder=\"Buscar por líder o iglesia...\"\n            className=\"w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm\"\n            value={searchTerm}\n            onChange={(e) => setSearchTerm(e.target.value)}\n          />\n        </div>\n        \n        <div className=\"flex flex-wrap items-center gap-2\">\n          <div className=\"flex items-center gap-2 text-sm text-slate-600 bg-white border border-slate-200 px-3 py-1.5 rounded-lg\">\n            <Filter className=\"w-4 h-4\" />\n            <select \n              className=\"outline-none bg-transparent\"\n              value={zoneFilter}\n              onChange={(e) => setZoneFilter(e.target.value)}\n            >\n              <option value=\"all\">Todas las Zonas</option>\n              {ZONES.map(z => <option key={z} value={z}>{z}</option>)}\n            </select>\n          </div>\n\n          <div className=\"flex items-center gap-2 text-sm text-slate-600 bg-white border border-slate-200 px-3 py-1.5 rounded-lg\">\n            <select \n              className=\"outline-none bg-transparent\"\n              value={meetingFilter}\n              onChange={(e) => setMeetingFilter(e.target.value)}\n            >\n              <option value=\"all\">Todas las Reuniones</option>\n              {meetings.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}\n            </select>\n          </div>\n\n          <button className=\"flex items-center gap-2 px-4 py-2 bg-slate-800 text-white rounded-lg text-sm font-medium hover:bg-slate-700 transition-colors\">\n            <FileDown className=\"w-4 h-4\" />\n            Exportar\n          </button>\n        </div>\n      </div>\n\n      <div className=\"overflow-x-auto\">\n        <table className=\"w-full text-left text-sm\">\n          <thead className=\"bg-slate-50 text-slate-500 uppercase text-xs font-semibold\">\n            <tr>\n              <th className=\"px-6 py-4\">Líder e Iglesia</th>\n              <th className=\"px-6 py-4\">Zona / Comunidad</th>\n              <th className=\"px-6 py-4 text-center\">Libros</th>\n              <th className=\"px-6 py-4\">Reunión Asignada</th>\n              <th className=\"px-6 py-4\">Estado</th>\n              <th className=\"px-6 py-4 text-right\">Acciones</th>\n            </tr>\n          </thead>\n          <tbody className=\"divide-y divide-slate-100\">\n            {filteredChurches.map(c => (\n              <tr key={c.id} className=\"hover:bg-slate-50 transition-colors\">\n                <td className=\"px-6 py-4\">\n                  <div>\n                    <p className=\"font-semibold text-slate-800\">{c.fullName}</p>\n                    <p className=\"text-slate-500 text-xs\">{c.churchName}</p>\n                    <p className=\"text-slate-400 text-xs\">{c.whatsapp}</p>\n                  </div>\n                </td>\n                <td className=\"px-6 py-4\">\n                  <p className=\"font-medium text-slate-700\">{c.zone}</p>\n                  <p className=\"text-slate-400 text-xs\">{c.community}</p>\n                </td>\n                <td className=\"px-6 py-4 text-center\">\n                  <span className=\"inline-block px-2.5 py-1 bg-blue-50 text-blue-700 rounded-full font-bold\">\n                    {c.bookQuantity}\n                  </span>\n                </td>\n                <td className=\"px-6 py-4\">\n                  <span className=\"text-slate-600 truncate max-w-[200px] block\">\n                    {getMeetingName(c.meetingId)}\n                  </span>\n                </td>\n                <td className=\"px-6 py-4\">\n                  <span className={`px-2.5 py-1 rounded-full text-xs font-medium border ${\n                    c.status === ContactStatus.SENT \n                    ? 'bg-emerald-50 text-emerald-700 border-emerald-100' \n                    : 'bg-amber-50 text-amber-700 border-amber-100'\n                  }`}>\n                    {c.status.toUpperCase()}\n                  </span>\n                </td>\n                <td className=\"px-6 py-4 text-right\">\n                  <div className=\"flex items-center justify-end gap-2\">\n                    <button \n                      onClick={() => onOpenMessenger(c)}\n                      className=\"p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors\"\n                      title=\"Enviar WhatsApp\"\n                    >\n                      <MessageCircle className=\"w-5 h-5\" />\n                    </button>\n                    <button className=\"p-2 text-slate-400 hover:bg-slate-100 rounded-lg transition-colors\">\n                      <MoreVertical className=\"w-5 h-5\" />\n                    </button>\n                  </div>\n                </td>\n              </tr>\n            ))}\n          </tbody>\n        </table>\n      </div>\n      \n      {filteredChurches.length === 0 && (\n        <div className=\"p-12 text-center\">\n          <p className=\"text-slate-400\">No se encontraron registros que coincidan con los filtros.</p>\n        </div>\n      )}\n    </div>\n  );\n};\n\nexport default ChurchManagement;\n"
            }
          ]
