              "replacement": "\nimport React from 'react';\nimport { Meeting, ChurchLeader } from '../types';\nimport { MapPin, Calendar, Clock, Plus, Users, ChevronRight } from 'lucide-react';\n\ninterface Props {\n  meetings: Meeting[];\n  churches: ChurchLeader[];\n  onSelectMeeting: (m: Meeting) => void;\n}\n\nconst MeetingManagement: React.FC<Props> = ({ meetings, churches, onSelectMeeting }) => {\n  const getChurchCount = (meetingId: string) => \n    churches.filter(c => c.meetingId === meetingId).length;\n\n  const getBookCount = (meetingId: string) => \n    churches.filter(c => c.meetingId === meetingId).reduce((s, c) => s + c.bookQuantity, 0);\n\n  return (\n    <div className=\"space-y-4\">\n      <div className=\"flex items-center justify-between mb-6\">\n        <h2 className=\"text-xl font-bold text-slate-800\">Programación de Reuniones</h2>\n        <button className=\"flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all font-medium\">\n          <Plus className=\"w-4 h-4\" />\n          Nueva Reunión\n        </button>\n      </div>\n\n      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n        {meetings.map(meeting => (\n          <div \n            key={meeting.id} \n            className=\"group bg-white rounded-xl shadow-sm border border-slate-100 hover:border-blue-300 hover:shadow-md transition-all cursor-pointer overflow-hidden\"\n            onClick={() => onSelectMeeting(meeting)}\n          >\n            <div className=\"p-5\">\n              <div className=\"flex items-start justify-between mb-4\">\n                <span className=\"px-3 py-1 bg-blue-50 text-blue-700 text-xs font-bold rounded-full uppercase tracking-wider\">\n                  {meeting.zone}\n                </span>\n                <ChevronRight className=\"w-5 h-5 text-slate-300 group-hover:text-blue-500 transition-colors\" />\n              </div>\n              \n              <h3 className=\"text-lg font-bold text-slate-800 mb-2 leading-snug group-hover:text-blue-600 transition-colors\">\n                {meeting.name}\n              </h3>\n              \n              <div className=\"space-y-2 mb-6\">\n                <div className=\"flex items-center gap-2 text-sm text-slate-500\">\n                  <Calendar className=\"w-4 h-4\" />\n                  {new Date(meeting.date).toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}\n                </div>\n                <div className=\"flex items-center gap-2 text-sm text-slate-500\">\n                  <Clock className=\"w-4 h-4\" />\n                  {meeting.time}\n                </div>\n                <div className=\"flex items-center gap-2 text-sm text-slate-600\">\n                  <MapPin className=\"w-4 h-4 text-red-500 shrink-0\" />\n                  <span className=\"truncate\">{meeting.venue}</span>\n                </div>\n              </div>\n\n              <div className=\"flex items-center justify-between pt-4 border-t border-slate-50\">\n                <div className=\"flex items-center gap-4\">\n                  <div className=\"text-center\">\n                    <p className=\"text-xs text-slate-400 font-medium uppercase\">Iglesias</p>\n                    <p className=\"text-lg font-bold text-slate-800\">{getChurchCount(meeting.id)}</p>\n                  </div>\n                  <div className=\"text-center border-l border-slate-100 pl-4\">\n                    <p className=\"text-xs text-slate-400 font-medium uppercase\">Libros</p>\n                    <p className=\"text-lg font-bold text-slate-800\">{getBookCount(meeting.id)}</p>\n                  </div>\n                </div>\n                <Users className=\"w-8 h-8 text-slate-100\" />\n              </div>\n            </div>\n          </div>\n        ))}\n      </div>\n    </div>\n  );\n};\n\nexport default MeetingManagement;\n"
