              "replacement": "\nimport React, { useState } from 'react';\nimport { Meeting, ChurchLeader } from '../types';\nimport { ZONES } from '../constants';\nimport { MapPin, Calendar, Clock, Plus, Users, ChevronRight, LayoutGrid, List } from 'lucide-react';\n\ninterface Props {\n  meetings: Meeting[];\n  churches: ChurchLeader[];\n  onSelectMeeting: (m: Meeting) => void;\n}\n\nconst MeetingManagement: React.FC<Props> = ({ meetings, churches, onSelectMeeting }) => {\n  const [selectedZone, setSelectedZone] = useState<string>('Todas');\n\n  const filteredMeetings = selectedZone === 'Todas' \n    ? meetings \n    : meetings.filter(m => m.zone === selectedZone);\n\n  const getChurchCount = (meetingId: string) => \n    churches.filter(c => c.meetingId === meetingId).length;\n\n  return (\n    <div className=\"space-y-6\">\n      <div className=\"flex items-center justify-between\">\n        <div>\n          <h2 className=\"text-xl font-bold text-slate-800\">Calendario Territorial</h2>\n          <p className=\"text-sm text-slate-500\">Planifica las reuniones por zonas geográficas</p>\n        </div>\n        <button className=\"flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all font-bold shadow-lg shadow-blue-100\">\n          <Plus className=\"w-4 h-4\" />\n          Nueva Reunión\n        </button>\n      </div>\n\n      <div className=\"flex items-center gap-2 bg-white p-2 rounded-2xl border border-slate-100 shadow-sm overflow-x-auto\">\n        <button \n          onClick={() => setSelectedZone('Todas')}\n          className={`px-4 py-2 text-sm font-bold rounded-xl whitespace-nowrap transition-all ${selectedZone === 'Todas' ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}\n        >\n          Todas\n        </button>\n        {ZONES.map(z => (\n          <button \n            key={z}\n            onClick={() => setSelectedZone(z)}\n            className={`px-4 py-2 text-sm font-bold rounded-xl whitespace-nowrap transition-all ${selectedZone === z ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}\n          >\n            {z}\n          </button>\n        ))}\n      </div>\n\n      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n        {filteredMeetings.map(meeting => (\n          <div \n            key={meeting.id} \n            className=\"group bg-white rounded-3xl shadow-sm border border-slate-100 hover:border-blue-300 hover:shadow-xl transition-all cursor-pointer overflow-hidden flex flex-col\"\n            onClick={() => onSelectMeeting(meeting)}\n          >\n            <div className=\"p-6 flex-1\">\n              <div className=\"flex items-center justify-between mb-4\">\n                <span className=\"px-3 py-1 bg-indigo-50 text-indigo-700 text-[10px] font-black rounded-full uppercase tracking-tighter\">\n                  {meeting.zone}\n                </span>\n                <div className=\"w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center group-hover:bg-blue-50 transition-colors\">\n                  <ChevronRight className=\"w-4 h-4 text-slate-300 group-hover:text-blue-500\" />\n                </div>\n              </div>\n              \n              <h3 className=\"text-xl font-black text-slate-800 mb-4 leading-tight group-hover:text-blue-600 transition-colors\">\n                {meeting.name}\n              </h3>\n              \n              <div className=\"space-y-3\">\n                <div className=\"flex items-center gap-3 text-sm text-slate-500\">\n                  <div className=\"w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center\">\n                    <Calendar className=\"w-4 h-4 text-slate-400\" />\n                  </div>\n                  <span className=\"font-medium\">\n                    {new Date(meeting.date).toLocaleDateString('es-ES', { weekday: 'short', month: 'long', day: 'numeric' })}\n                  </span>\n                </div>\n                <div className=\"flex items-center gap-3 text-sm text-slate-500\">\n                  <div className=\"w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center\">\n                    <Clock className=\"w-4 h-4 text-slate-400\" />\n                  </div>\n                  <span className=\"font-medium\">{meeting.time}</span>\n                </div>\n                <div className=\"flex items-center gap-3 text-sm text-slate-600\">\n                  <div className=\"w-8 h-8 rounded-lg bg-red-50 flex items-center justify-center\">\n                    <MapPin className=\"w-4 h-4 text-red-400\" />\n                  </div>\n                  <span className=\"font-semibold truncate\">{meeting.venue}</span>\n                </div>\n              </div>\n            </div>\n\n            <div className=\"p-4 bg-slate-50/50 border-t border-slate-100 flex items-center justify-between\">\n              <div className=\"flex items-center gap-2\">\n                <Users className=\"w-4 h-4 text-slate-400\" />\n                <span className=\"text-sm font-bold text-slate-700\">{getChurchCount(meeting.id)}</span>\n                <span className=\"text-xs text-slate-400\">Líderes</span>\n              </div>\n              <div className=\"h-2 w-24 bg-slate-200 rounded-full overflow-hidden\">\n                <div className=\"h-full bg-blue-500 rounded-full\" style={{width: '65%'}}></div>\n              </div>\n            </div>\n          </div>\n        ))}\n\n        {filteredMeetings.length === 0 && (\n          <div className=\"col-span-full py-12 flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-200 rounded-3xl\">\n            <Calendar className=\"w-12 h-12 mb-4 opacity-10\" />\n            <p className=\"font-medium\">No hay reuniones programadas en esta zona.</p>\n          </div>\n        )}\n      </div>\n    </div>\n  );\n};\n\nexport default MeetingManagement;\n"
