              "target": "",
              "replacement": "\nimport React, { useState } from 'react';\nimport { \n  LayoutDashboard, \n  Church, \n  CalendarDays, \n  MessageSquareText, \n  Settings, \n  LogOut, \n  Menu, \n  Bell,\n  Search,\n  Waves\n} from 'lucide-react';\nimport { ViewType, ChurchLeader, Meeting, ContactStatus } from './types';\nimport { INITIAL_CHURCHES, INITIAL_MEETINGS } from './constants';\nimport Dashboard from './components/Dashboard';\nimport ChurchManagement from './components/ChurchManagement';\nimport MeetingManagement from './components/MeetingManagement';\nimport WhatsAppMessenger from './components/WhatsAppMessenger';\n\nconst App: React.FC = () => {\n  const [currentView, setCurrentView] = useState<ViewType>('dashboard');\n  const [isSidebarOpen, setIsSidebarOpen] = useState(true);\n  const [churches, setChurches] = useState<ChurchLeader[]>(INITIAL_CHURCHES);\n  const [meetings] = useState<Meeting[]>(INITIAL_MEETINGS);\n  const [selectedChurch, setSelectedChurch] = useState<ChurchLeader | undefined>();\n\n  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);\n\n  const handleOpenMessenger = (church: ChurchLeader) => {\n    setSelectedChurch(church);\n    setCurrentView('whatsapp');\n  };\n\n  const handleAddChurch = (churchData: Omit<ChurchLeader, 'id' | 'status'>) => {\n    const newChurch: ChurchLeader = {\n      ...churchData,\n      id: `c${Date.now()}`,\n      status: ContactStatus.PENDING\n    };\n    setChurches(prev => [newChurch, ...prev]);\n  };\n\n  const handleBulkImport = (newChurches: Omit<ChurchLeader, 'id' | 'status'>[]) => {\n    const formatted: ChurchLeader[] = newChurches.map((c, i) => ({\n      ...c,\n      id: `imp-${Date.now()}-${i}`,\n      status: ContactStatus.PENDING\n    }));\n    setChurches(prev => [...formatted, ...prev]);\n  };\n\n  const handleSent = (churchId: string) => {\n    setChurches(prev => prev.map(c => \n      c.id === churchId \n      ? { ...c, status: ContactStatus.SENT, lastContactDate: new Date().toISOString() } \n      : c\n    ));\n  };\n\n  const renderContent = () => {\n    switch (currentView) {\n      case 'dashboard':\n        return <Dashboard churches={churches} meetings={meetings} />;\n      case 'churches':\n        return <ChurchManagement \n                  churches={churches} \n                  meetings={meetings} \n                  onOpenMessenger={handleOpenMessenger}\n                  onAddChurch={handleAddChurch}\n                  onBulkImport={handleBulkImport}\n               />;\n      case 'meetings':\n        return <MeetingManagement meetings={meetings} churches={churches} onSelectMeeting={(m) => {\n          // Additional logic for meeting selection\n        }} />;\n      case 'whatsapp':\n        const currentMeeting = meetings.find(m => m.id === selectedChurch?.meetingId);\n        return <WhatsAppMessenger church={selectedChurch} meeting={currentMeeting} onSent={handleSent} />;\n      default:\n        return <Dashboard churches={churches} meetings={meetings} />;\n    }\n  };\n\n  const menuItems = [\n    { id: 'dashboard', label: 'Dashboard', icon: <LayoutDashboard className=\"w-5 h-5\" /> },\n    { id: 'churches', label: 'Iglesias', icon: <Church className=\"w-5 h-5\" /> },\n    { id: 'meetings', label: 'Reuniones', icon: <CalendarDays className=\"w-5 h-5\" /> },\n    { id: 'whatsapp', label: 'Mensajería', icon: <MessageSquareText className=\"w-5 h-5\" /> },\n  ];\n\n  return (\n    <div className=\"flex h-screen bg-slate-50 overflow-hidden font-sans\">\n      {/* Sidebar */}\n      <aside className={`\n        ${isSidebarOpen ? 'w-72' : 'w-24'} \n        bg-white text-slate-500 transition-all duration-300 flex flex-col h-full border-r border-slate-100 shadow-sm z-30\n      `}>\n        <div className=\"p-8 flex items-center gap-4\">\n          <div className=\"bg-blue-600 p-2.5 rounded-2xl text-white shadow-lg shadow-blue-100 flex-shrink-0\">\n            <Waves className=\"w-6 h-6\" />\n          </div>\n          {isSidebarOpen && <span className=\"font-black text-slate-800 text-xl tracking-tighter uppercase\">Peces<span className=\"text-blue-600\">.io</span></span>}\n        </div>\n\n        <nav className=\"flex-1 px-4 py-4 space-y-1\">\n          {menuItems.map((item) => (\n            <button\n              key={item.id}\n              onClick={() => setCurrentView(item.id as ViewType)}\n              className={`\n                w-full flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all duration-200\n                ${currentView === item.id \n                  ? 'bg-slate-900 text-white font-bold shadow-xl shadow-slate-200' \n                  : 'hover:bg-slate-50 text-slate-400 hover:text-slate-600'}\n              `}\n            >\n              <div className={currentView === item.id ? 'text-blue-400' : ''}>{item.icon}</div>\n              {isSidebarOpen && <span>{item.label}</span>}\n            </button>\n          ))}\n        </nav>\n\n        <div className=\"p-4 space-y-2 mb-4\">\n          <button className=\"w-full flex items-center gap-4 px-4 py-3 rounded-2xl hover:bg-slate-50 transition-all text-slate-400 font-medium\">\n            <Settings className=\"w-5 h-5\" />\n            {isSidebarOpen && <span>Ajustes</span>}\n          </button>\n          <button className=\"w-full flex items-center gap-4 px-4 py-3 rounded-2xl hover:bg-red-50 hover:text-red-500 transition-all text-slate-400 font-medium\">\n            <LogOut className=\"w-5 h-5\" />\n            {isSidebarOpen && <span>Salir</span>}\n          </button>\n        </div>\n      </aside>\n\n      {/* Main Content */}\n      <main className=\"flex-1 flex flex-col min-w-0 bg-[#fbfcfd]\">\n        <header className=\"h-24 bg-white/80 backdrop-blur-md border-b border-slate-100 flex items-center justify-between px-10 shrink-0 sticky top-0 z-20\">\n          <div className=\"flex items-center gap-6\">\n            <button onClick={toggleSidebar} className=\"p-3 hover:bg-slate-50 rounded-2xl text-slate-400 transition-colors\">\n              <Menu className=\"w-6 h-6\" />\n            </button>\n            <div>\n              <h1 className=\"text-2xl font-black text-slate-800 tracking-tight capitalize\">\n                {menuItems.find(i => i.id === currentView)?.label}\n              </h1>\n              <p className=\"text-[10px] font-black text-slate-300 tracking-[0.2em] uppercase\">Ecosistema Peces v2.4</p>\n            </div>\n          </div>\n\n          <div className=\"flex items-center gap-6\">\n            <div className=\"relative hidden xl:block\">\n               <Search className=\"absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300\" />\n               <input \n                type=\"text\" \n                placeholder=\"Comando rápido...\" \n                className=\"pl-12 pr-6 py-3 bg-slate-50 border border-slate-100 rounded-2xl text-xs w-72 focus:ring-4 focus:ring-blue-50 outline-none transition-all font-medium\"\n               />\n            </div>\n            <div className=\"flex items-center gap-2\">\n              <button className=\"p-3 relative hover:bg-slate-50 rounded-2xl text-slate-400 transition-all\">\n                <Bell className=\"w-5 h-5\" />\n                <span className=\"absolute top-3 right-3 w-2 h-2 bg-blue-500 rounded-full border-2 border-white\"></span>\n              </button>\n              <div className=\"h-12 w-12 rounded-2xl bg-gradient-to-tr from-slate-200 to-slate-100 border-2 border-white shadow-sm flex items-center justify-center font-bold text-slate-400\">\n                JD\n              </div>\n            </div>\n          </div>\n        </header>\n\n        <div className=\"flex-1 overflow-y-auto p-10\">\n          <div className=\"max-w-6xl mx-auto\">\n            {renderContent()}\n          </div>\n        </div>\n      </main>\n    </div>\n  );\n};\n\nexport default App;\n"
