              "target": "",
              "replacement": "\n/* --- FILE: services/geminiService.ts --- */\nimport { GoogleGenAI } from \"@google/genai\";\nimport { ChurchLeader, Meeting } from \"../types\";\n\nconst ai = new GoogleGenAI({ apiKey: process.env.API_KEY });\n\n/**\n * Genera una plantilla de invitación utilizando IA, con restricciones estrictas\n * para no inventar información fuera de la base de datos.\n */\nexport const generateWhatsAppTemplate = async (meeting: Meeting, tone: string = 'pastoral y formal'): Promise<string> => {\n  try {\n    const prompt = `Actúa como un coordinador logístico de \"Ecosistema Peces\". \n    Tu tarea es redactar una plantilla de invitación para WhatsApp para una reunión de líderes.\n    \n    REGLAS CRÍTICAS DE \"SOLO DATOS\":\n    1. NO INVENTES NADA. No menciones comida, refrigerios, transporte, parqueo, vestimenta ni actividades adicionales.\n    2. LIMITATE ESTRICTAMENTE a la información proporcionada en la base de datos y el contexto del evento.\n    3. Si un dato no existe (como la hora o fecha), usa la etiqueta correspondiente para que el sistema lo rellene.\n    4. Usa ÚNICAMENTE estas etiquetas para los datos variables:\n       - {{nombre_completo}}: Nombre del pastor o líder.\n       - {{nombre_iglesia}}: Nombre de la congregación.\n       - {{comunidad}}: Sector o comunidad del líder.\n       - {{zona}}: Zona territorial asignada.\n       - {{reunion_asignada}}: Nombre del grupo de reunión (Columna K/H).\n       - {{cantidad_libros}}: Cantidad de libros registrados.\n       - {{entidad_responsable}}: Institución o entidad responsable.\n       - {{fecha}}: Fecha programada.\n       - {{hora}}: Hora programada.\n       - {{sede}}: Dirección o lugar de la reunión.\n\n    CONTEXTO DEL EVENTO (No añadir nada fuera de esto):\n    - Grupo: ${meeting.name}\n    - Zona: ${meeting.zone}\n    - Fecha: ${meeting.date || '[Pendiente]'}\n    - Hora: ${meeting.time || '[Pendiente]'}\n    - Sede: ${meeting.venue || '[Pendiente]'}\n    \n    Tono: ${tone}. La invitación debe ser corta, profesional y basada 100% en hechos.`;\n\n    const response = await ai.models.generateContent({\n      model: 'gemini-3-flash-preview',\n      contents: prompt,\n    });\n    \n    return response.text?.trim() || 'Error al generar plantilla.';\n  } catch (error) {\n    console.error(\"Gemini Error:\", error);\n    return `Bendiciones {{nombre_completo}}. Le invitamos a la reunión de {{reunion_asignada}} el día {{fecha}} a las {{hora}} en {{sede}}. Invitación para la zona {{zona}}.`;\n  }\n};\n\n/**\n * Sustituye las etiquetas de la plantilla por los valores reales de la base de datos.\n */\nexport const parseTemplate = (template: string, church: ChurchLeader, meeting: Meeting): string => {\n  let message = template;\n  \n  // Mapeo de datos del líder e iglesia (Provenientes del Excel)\n  message = message.replace(/{{nombre_completo}}/g, church.fullName || '');\n  message = message.replace(/{{nombre_iglesia}}/g, church.churchName || '');\n  message = message.replace(/{{comunidad}}/g, church.community || '');\n  message = message.replace(/{{zona}}/g, church.zone || '');\n  message = message.replace(/{{cantidad_libros}}/g, String(church.booksCount || 0));\n  message = message.replace(/{{entidad_responsable}}/g, church.responsibleEntity || '');\n  message = message.replace(/{{reunion_asignada}}/g, meeting.name || church.meetingId || '');\n  \n  // Mapeo de datos del evento programado en el calendario\n  message = message.replace(/{{fecha}}/g, meeting.date || 'Por definir');\n  message = message.replace(/{{hora}}/g, meeting.time || 'Por definir');\n  message = message.replace(/{{sede}}/g, meeting.venue || 'Por definir');\n  \n  return message;\n};\n"
